CREATE TABLE IF NOT EXISTS "users" (
	"user_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"user_name" VARCHAR(255) NOT NULL,
	"user_phone" VARCHAR(20) NOT NULL UNIQUE,
	"user_email" VARCHAR(255) UNIQUE,
	"password_hash" TEXT NOT NULL,
	"user_is_active_flag" BOOLEAN NOT NULL,
	"user_role_id" INTEGER NOT NULL,
	"dealer_id" INTEGER,
	"created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	"updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	PRIMARY KEY("user_id")
);

COMMENT ON TABLE "users" IS 'users login into the application. ';


CREATE TABLE IF NOT EXISTS "user_roles" (
	"role_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"role_name" VARCHAR(255) NOT NULL UNIQUE,
	"role_desc" TEXT,
	"created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	"updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	PRIMARY KEY("role_id")
);

COMMENT ON TABLE "user_roles" IS 'user roles';


CREATE TABLE IF NOT EXISTS "dealers" (
	"dealer_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"dealer_name" VARCHAR(255) NOT NULL,
	"dealer_code" VARCHAR(50) NOT NULL UNIQUE,
	"dealer_phone" VARCHAR(20),
	"dealer_address" TEXT,
	"dealer_is_active_flag" BOOLEAN NOT NULL DEFAULT TRUE,
	"created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	"updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	PRIMARY KEY("dealer_id")
);

COMMENT ON TABLE "dealers" IS 'Master Entity, 
One Dealer → can have multiple Users';


CREATE TABLE IF NOT EXISTS "products" (
	"product_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"product_name" VARCHAR(255) NOT NULL UNIQUE,
	"product_desc" TEXT,
	"product_is_active_flag" BOOLEAN NOT NULL,
	"created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	"updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	PRIMARY KEY("product_id")
);

COMMENT ON TABLE "products" IS 'Master Entity';


CREATE TABLE IF NOT EXISTS "locations" (
	"location_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"location_name" VARCHAR(255) NOT NULL UNIQUE,
	"location_desc" TEXT,
	"location_is_active_flag" BOOLEAN NOT NULL,
	"created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	"updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	PRIMARY KEY("location_id")
);

COMMENT ON TABLE "locations" IS 'Master Entity';


CREATE TABLE IF NOT EXISTS "dealer_orders" (
	"order_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"dealer_id" INTEGER NOT NULL,
	"product_id" INTEGER NOT NULL,
	"source_location_id" INTEGER NOT NULL,
	"order_quantity" INTEGER NOT NULL CHECK(order_quantity > 0),
	"order_start_date" TIMESTAMP NOT NULL,
	"order_status" VARCHAR(255) NOT NULL,
	"created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	"updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	PRIMARY KEY("order_id")
);

COMMENT ON TABLE "dealer_orders" IS 'Transaction Entity';


CREATE TABLE IF NOT EXISTS "order_dispatch" (
	"dispatch_id" INTEGER NOT NULL GENERATED BY DEFAULT AS IDENTITY,
	"order_id" INTEGER NOT NULL,
	"driver_id" INTEGER NOT NULL,
	"dispatch_vehicle_number" VARCHAR(255),
	"built_number" VARCHAR(255),
	"dispatch_receipt" TEXT,
	"created_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	"updated_at" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
	PRIMARY KEY("dispatch_id")
);

COMMENT ON TABLE "order_dispatch" IS 'Transaction Entity';

ALTER TABLE "users"
ADD FOREIGN KEY("user_role_id") REFERENCES "user_roles"("role_id")
ON UPDATE NO ACTION ON DELETE RESTRICT;
ALTER TABLE "dealer_orders"
ADD FOREIGN KEY("dealer_id") REFERENCES "dealers"("dealer_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "dealer_orders"
ADD FOREIGN KEY("product_id") REFERENCES "products"("product_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "dealer_orders"
ADD FOREIGN KEY("source_location_id") REFERENCES "locations"("location_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;
ALTER TABLE "users"
ADD FOREIGN KEY("dealer_id") REFERENCES "dealers"("dealer_id")
ON UPDATE NO ACTION ON DELETE NO ACTION;

